    //asis호출없어 막음
    //scwin.f_openPopUp('1',ed_mgntAcctDeptCd,txt_mgntAcctDeptNm,'T');

};

scwin.btn_trigger1_onclick = function (e) {
    scwin.f_Retrieve();

};
